import source


def test_source_module_imports():
    assert source is not None


def test_powerset_correctness():
    # The powerset of [1, 2] should contain 4 subsets: [], [1], [2], [1, 2]
    result = source.powerset([1, 2])
    # Convert each subset to a sorted tuple for comparison ignoring order of subsets
    result_set = {tuple(sorted(sub)) for sub in result}
    expected_set = {(), (1,), (2,), (1, 2)}
    assert result_set == expected_set
    assert len(result) == 4
